CREATE TABLE IF NOT EXISTS goals (id SERIAL PRIMARY KEY, "firebaseUid" VARCHAR(128) NOT NULL, title VARCHAR(255) NOT NULL, amount DOUBLE PRECISION NOT NULL, currency VARCHAR(3) NOT NULL, deadline DATE NULL, "createdAt" TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL, "completedAt" TIMESTAMP NULL);
CREATE TABLE IF NOT EXISTS transactions (id SERIAL PRIMARY KEY, "firebaseUid" VARCHAR(128) NOT NULL, currency VARCHAR(10) NOT NULL, amount DOUBLE PRECISION NOT NULL, description VARCHAR(255) NULL, category VARCHAR(50) NOT NULL, "createdAt" TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL, "goalId" INT NULL, CONSTRAINT fk_transactions_goalid__id FOREIGN KEY ("goalId") REFERENCES goals(id) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE SEQUENCE IF NOT EXISTS Transactions_id_seq START WITH 1 MINVALUE 1 MAXVALUE 9223372036854775807;
CREATE SEQUENCE IF NOT EXISTS Goals_id_seq START WITH 1 MINVALUE 1 MAXVALUE 9223372036854775807;